264		protected getTimestamp(): string {
265			return dateTimeFormatter.format(Date.now());
266		}
267	
268		protected printMessages(
269			messages: unknown[],
270			context = '',
271			logLevel: LogLevel = 'log',
272			writeStreamType?: 'stdout' | 'stderr',
273			errorStack?: unknown,
274		) {
275			const correlationId = (correlator.getId() as string) || randomUUID();
276	
277			messages.forEach((message) => {
278				if (this.options.json) {
279					// @ts-ignore
280					this.printAsJson(message, correlationId, {
281						context,
282						logLevel,
283						writeStreamType,
284						errorStack,
285					});
286					return;
287				}
288				const pidMessage = this.formatPid(process.pid);
289				const contextMessage = this.formatContext(context);
290				const timestampDiff = this.updateAndGetTimestampDiff();
291				const formattedLogLevel = logLevel.toUpperCase().padStart(7, ' ');
292				const formattedMessage = this.formatMessage(
293					logLevel,
294					message,
295					correlationId,
296					pidMessage,
297					formattedLogLevel,
298					contextMessage,
299					timestampDiff,
300				);
301	
302				process[writeStreamType ?? 'stdout'].write(formattedMessage);
303			});
304		}
305	
306		protected printAsJson(
307			message: unknown,
308			correlationId: string,
309			options: {
310				context: string;
311				logLevel: LogLevel;
312				writeStreamType?: 'stdout' | 'stderr';
313				errorStack?: unknown;
314			},
315		) {
316			type JsonLogObject = {
317				level: LogLevel;
318				pid: number;
319				timestamp: number;
320				correlationId: string;
321				message: unknown;
322				context?: string;
323				stack?: unknown;
324			};
325	
326			const logObject: JsonLogObject = {
327				level: options.logLevel,
328				pid: process.pid,
329				timestamp: Date.now(),
330				correlationId,
331				message,
332			};
333	
334			if (options.context) {
335				logObject.context = options.context;
336			}
337	
338			if (options.errorStack) {
339				logObject.stack = options.errorStack;
340			}
341	
342			const formattedMessage =
343				!this.options.colors && this.inspectOptions.compact === true
344					? JSON.stringify(logObject, this.stringifyReplacer)
345					: inspect(logObject, this.inspectOptions);
346			process[options.writeStreamType ?? 'stdout'].write(`${formattedMessage}\n`);
347		}
348	
349		protected formatPid(pid: number) {
350			return `[${this.options.prefix}] ${pid}  - `;
351		}
352	
353		protected formatContext(context: string): string {
354			if (!context) {
355				return '';
356			}
357	
358			context = `[${context}] `;
359			return this.options.colors ? yellow(context) : context;
360		}
361	
362		protected formatMessage(
363			logLevel: LogLevel,
364			message: unknown,
365			correlationId: string,
366			pidMessage: string,
367			formattedLogLevel: string,
368			contextMessage: string,
369			timestampDiff: string,
370		) {
371			const output = this.stringifyMessage(message, logLevel);
372			pidMessage = this.colorize(pidMessage, logLevel);
373			formattedLogLevel = this.colorize(formattedLogLevel, logLevel);
374			return `${pidMessage}${this.getTimestamp()} ${formattedLogLevel} ${correlationId}${contextMessage}${output}${timestampDiff}\n`;
375		}
376	
377		protected stringifyMessage(message: unknown, logLevel: LogLevel): string {
378			if (isFunction(message)) {
379				const messageAsStr = Function.prototype.toString.call(message);
380				const isClass = messageAsStr.startsWith('class ');
381				if (isClass) {
382					// @ts-ignore
383					return this.stringifyMessage(message.name, logLevel);
384				}
385				// @ts-ignore
386				return this.stringifyMessage(message(), logLevel);
387			}
388	
389			if (typeof message === 'string') {
390				return this.colorize(message, logLevel);
391			}
392	
393			const outputText = inspect(message, this.inspectOptions);
394			if (isPlainObject(message)) {
395				return `Object(${Object.keys(message).length}) ${outputText}`;
396			}
397			if (Array.isArray(message)) {
398				return `Array(${message.length}) ${outputText}`;
399			}
400			return outputText;
401		}
402	
403		protected colorize(message: string, logLevel: LogLevel) {
404			if (!this.options.colors || this.options.json) {
405				return message;
406			}
407			const color = this.getColorByLogLevel(logLevel);
408			return color(message);
409		}
410	
411		protected printStackTrace(stack: string) {
412			if (!stack || this.options.json) {
413				return;
414			}
415			process.stderr.write(`${stack}\n`);
416		}
417	
418		protected updateAndGetTimestampDiff(): string {
419			// @ts-ignore
420			const includeTimestamp = ConsoleLogger.lastTimestampAt && this.options?.timestamp;
421			const result = includeTimestamp
422				? // @ts-ignore
423					this.formatTimestampDiff(Date.now() - ConsoleLogger.lastTimestampAt!)
424				: '';
425			// @ts-ignore
426			ConsoleLogger.lastTimestampAt = Date.now();
427			return result;
428		}
429	
430		protected formatTimestampDiff(timestampDiff: number) {
431			const formattedDiff = ` +${timestampDiff}ms`;
432			return this.options.colors ? yellow(formattedDiff) : formattedDiff;
433		}
434	
435		protected getInspectOptions() {
436			let breakLength = this.options.breakLength;
437			if (typeof breakLength === 'undefined') {
438				breakLength = this.options.colors
439					? this.options.compact
440						? Infinity
441						: undefined
442					: this.options.compact === false
443						? undefined
444						: Infinity;
445			}
446	
447			const inspectOptions: InspectOptions = {
448				depth: this.options.depth ?? DEFAULT_DEPTH,
449				sorted: this.options.sorted,
450				showHidden: this.options.showHidden,
451				compact: this.options.compact ?? (this.options.json ? true : false),
452				colors: this.options.colors,
453				breakLength,
454			};
455	
456			if (this.options.maxArrayLength) {
457				inspectOptions.maxArrayLength = this.options.maxArrayLength;
458			}
459			if (this.options.maxStringLength) {
460				inspectOptions.maxStringLength = this.options.maxStringLength;
461			}
462	
463			return inspectOptions;
464		}
465	
466		protected stringifyReplacer(_: string, value: unknown) {
467			if (typeof value === 'bigint') {
468				return value.toString();
469			}
470			if (typeof value === 'symbol') {
471				return value.toString();
472			}
473	
474			if (value instanceof Map || value instanceof Set || value instanceof Error) {
475				return `${inspect(value, this.inspectOptions)}`;
476			}
477			return value;
478		}
479	
480		private getContextAndMessagesToPrint(args: unknown[]) {
481			if (args?.length <= 1) {
482				return { messages: args, context: this.context };
483			}
484			const lastElement = args[args.length - 1];
485			const isContext = isString(lastElement);
486			if (!isContext) {
487				return { messages: args, context: this.context };
488			}
489			return {
490				context: lastElement,
491				messages: args.slice(0, args.length - 1),
492			};
493		}
494	
495		private getContextAndStackAndMessagesToPrint(args: unknown[]) {
496			if (args.length === 2) {
497				return this.isStackFormat(args[1])
498					? {
499							messages: [args[0]],
500							stack: args[1] as string,
501							context: this.context,
502						}
503					: {
504							messages: [args[0]],
505							context: args[1] as string,
506						};
507			}
508	
509			const { messages, context } = this.getContextAndMessagesToPrint(args);
510			if (messages?.length <= 1) {
511				return { messages, context };
512			}
513			const lastElement = messages[messages.length - 1];
514			const isStack = isString(lastElement);
515			if (!isStack && !isUndefined(lastElement)) {
516				return { messages, context };
517			}
518			return {
519				stack: lastElement,
520				messages: messages.slice(0, messages.length - 1),
521				context,
522			};
523		}
524	
525		private isStackFormat(stack: unknown) {
526			if (!isString(stack) && !isUndefined(stack)) {
527				return false;
528			}
529	
530			return /^(.)+\n\s+at .+:\d+:\d+/.test(stack!);
531		}
532	
533		private getColorByLogLevel(level: LogLevel) {
534			switch (level) {
535				case 'debug':
536					return clc.magentaBright;
537				case 'warn':
538					return clc.yellow;
539				case 'error':
540					return clc.red;
541				case 'verbose':
542					return clc.cyanBright;
543				case 'fatal':
544					return clc.bold;
545				default:
546					return clc.green;
547			}
548		}
549	}
