import {
	ConsoleLogger,
	ConsoleLoggerOptions,
	Injectable,
	LoggerService,
	LogLevel,
	Optional,
} from '@nestjs/common';
import { correlator } from 'correlation-id-ts';
import { randomUUID } from 'node:crypto';
import { inspect, InspectOptions } from 'node:util';

const LOG_LEVEL_VALUES: Record<LogLevel, number> = {
	verbose: 0,
	debug: 1,
	log: 2,
	warn: 3,
	error: 4,
	fatal: 5,
};

export function isLogLevelEnabled(
	targetLevel: LogLevel,
	logLevels: LogLevel[] | undefined,
): boolean {
	if (!logLevels || (Array.isArray(logLevels) && logLevels?.length === 0)) {
		return false;
	}
	if (logLevels.includes(targetLevel)) {
		return true;
	}
	const highestLogLevelValue = logLevels
		.map((level) => LOG_LEVEL_VALUES[level])
		.sort((a, b) => b - a)?.[0];

	const targetLevelValue = LOG_LEVEL_VALUES[targetLevel];
	return targetLevelValue >= highestLogLevelValue!;
}

export const isUndefined = (obj: any): obj is undefined => typeof obj === 'undefined';

export const isObject = (fn: any): fn is object => !isNil(fn) && typeof fn === 'object';

export const isPlainObject = (fn: any): fn is object => {
	if (!isObject(fn)) {
		return false;
	}
	const proto = Object.getPrototypeOf(fn);
	if (proto === null) {
		return true;
	}
	const ctor =
		Object.prototype.hasOwnProperty.call(proto, 'constructor') && proto.constructor;
	return (
		typeof ctor === 'function' &&
		ctor instanceof ctor &&
		Function.prototype.toString.call(ctor) === Function.prototype.toString.call(Object)
	);
};

export const addLeadingSlash = (path?: string): string =>
	path && typeof path === 'string'
		? path.charAt(0) !== '/' && path.substring(0, 2) !== '{/'
			? '/' + path
			: path
		: '';

export const normalizePath = (path?: string): string =>
	path
		? path.startsWith('/')
			? ('/' + path.replace(/\/+$/, '')).replace(/\/+/g, '/')
			: '/' + path.replace(/\/+$/, '')
		: '/';

export const stripEndSlash = (path: string): string =>
	path.endsWith('/') ? path.slice(0, -1) : path;

export const isFunction = (val: unknown): val is Function => typeof val === 'function';
export const isString = (val: any): val is string => typeof val === 'string';
export const isNumber = (val: any): val is number => typeof val === 'number';
export const isConstructor = (val: any): boolean => val === 'constructor';
export const isNil = (val: any): val is null | undefined =>
	isUndefined(val) || val === null;
export const isEmpty = (array: any): boolean => !(array && array.length > 0);
export const isSymbol = (val: any): val is symbol => typeof val === 'symbol';

const DEFAULT_DEPTH = 5;

const DEFAULT_LOG_LEVELS: LogLevel[] = [
	'log',
	'error',
	'warn',
	'debug',
	'verbose',
	'fatal',
];

const dateTimeFormatter = new Intl.DateTimeFormat(undefined, {
	year: 'numeric',
	hour: 'numeric',
	minute: 'numeric',
	second: 'numeric',
	day: '2-digit',
	month: '2-digit',
});

type ColorTextFn = (text: string) => string;

const isColorAllowed = true;
const colorIfAllowed = (colorFn: ColorTextFn) => (text: string) =>
	isColorAllowed ? colorFn(text) : text;

const clc = {
	bold: colorIfAllowed((text: string) => `\x1B[1m${text}\x1B[0m`),
	green: colorIfAllowed((text: string) => `\x1B[32m${text}\x1B[39m`),
	yellow: colorIfAllowed((text: string) => `\x1B[33m${text}\x1B[39m`),
	red: colorIfAllowed((text: string) => `\x1B[31m${text}\x1B[39m`),
	magentaBright: colorIfAllowed((text: string) => `\x1B[95m${text}\x1B[39m`),
	cyanBright: colorIfAllowed((text: string) => `\x1B[96m${text}\x1B[39m`),
};
const yellow = colorIfAllowed((text: string) => `\x1B[38;5;3m${text}\x1B[39m`);

@Injectable()
export class RecoConsoleLogger implements LoggerService {
	protected options: ConsoleLoggerOptions;
	protected context?: string;
	protected originalContext?: string;
	protected inspectOptions: InspectOptions;
	protected static lastTimestampAt?: number;

	constructor();
	constructor(context: string);
	constructor(options: ConsoleLoggerOptions);
	constructor(context: string, options: ConsoleLoggerOptions);
	constructor(
		@Optional()
		contextOrOptions?: string | ConsoleLoggerOptions,
		@Optional()
		options?: ConsoleLoggerOptions,
	) {
		let [context, opts] = isString(contextOrOptions)
			? [contextOrOptions, options]
			: options
				? [undefined, options]
				: [contextOrOptions?.context, contextOrOptions];

		opts = opts ?? {};
		opts.logLevels ??= DEFAULT_LOG_LEVELS;
		opts.colors ??= opts.colors ?? (opts.json ? false : true);
		opts.prefix ??= 'Nest';

		this.options = opts;
		this.inspectOptions = this.getInspectOptions();

		if (context) {
			this.context = context;
			this.originalContext = context;
		}
	}

	log(message: any, context?: string): void;
	log(message: any, ...optionalParams: [...any, string?]): void;
	log(message: any, ...optionalParams: any[]) {
		if (!this.isLevelEnabled('log')) {
			return;
		}
		const { messages, context } = this.getContextAndMessagesToPrint([
			message,
			...optionalParams,
		]);
		this.printMessages(messages, context, 'log');
	}

	error(message: any, stackOrContext?: string): void;
	error(message: any, stack?: string, context?: string): void;
	error(message: any, ...optionalParams: [...any, string?, string?]): void;
	error(message: any, ...optionalParams: any[]) {
		if (!this.isLevelEnabled('error')) {
			return;
		}
		const { messages, context, stack } = this.getContextAndStackAndMessagesToPrint([
			message,
			...optionalParams,
		]);

		this.printMessages(messages, context, 'error', 'stderr', stack);
		this.printStackTrace(stack!);
	}

	warn(message: any, context?: string): void;
	warn(message: any, ...optionalParams: [...any, string?]): void;
	warn(message: any, ...optionalParams: any[]) {
		if (!this.isLevelEnabled('warn')) {
			return;
		}
		const { messages, context } = this.getContextAndMessagesToPrint([
			message,
			...optionalParams,
		]);
		this.printMessages(messages, context, 'warn');
	}

	debug(message: any, context?: string): void;
	debug(message: any, ...optionalParams: [...any, string?]): void;
	debug(message: any, ...optionalParams: any[]) {
		if (!this.isLevelEnabled('debug')) {
			return;
		}
		const { messages, context } = this.getContextAndMessagesToPrint([
			message,
			...optionalParams,
		]);
		this.printMessages(messages, context, 'debug');
	}

	verbose(message: any, context?: string): void;
	verbose(message: any, ...optionalParams: [...any, string?]): void;
	verbose(message: any, ...optionalParams: any[]) {
		if (!this.isLevelEnabled('verbose')) {
			return;
		}
		const { messages, context } = this.getContextAndMessagesToPrint([
			message,
			...optionalParams,
		]);
		this.printMessages(messages, context, 'verbose');
	}

	fatal(message: any, context?: string): void;
	fatal(message: any, ...optionalParams: [...any, string?]): void;
	fatal(message: any, ...optionalParams: any[]) {
		if (!this.isLevelEnabled('fatal')) {
			return;
		}
		const { messages, context } = this.getContextAndMessagesToPrint([
			message,
			...optionalParams,
		]);
		this.printMessages(messages, context, 'fatal');
	}

	setLogLevels(levels: LogLevel[]) {
		if (!this.options) {
			this.options = {};
		}
		this.options.logLevels = levels;
	}

	setContext(context: string) {
		this.context = context;
	}

	resetContext() {
		// @ts-ignore
		this.context = this.originalContext;
	}

	isLevelEnabled(level: LogLevel): boolean {
		const logLevels = this.options?.logLevels;
		return isLogLevelEnabled(level, logLevels);
	}

	protected getTimestamp(): string {
		return dateTimeFormatter.format(Date.now());
	}

	protected printMessages(
		messages: unknown[],
		context = '',
		logLevel: LogLevel = 'log',
		writeStreamType?: 'stdout' | 'stderr',
		errorStack?: unknown,
	) {
		const correlationId = (correlator.getId() as string) || randomUUID();

		messages.forEach((message) => {
			if (this.options.json) {
				// @ts-ignore
				this.printAsJson(message, correlationId, {
					context,
					logLevel,
					writeStreamType,
					errorStack,
				});
				return;
			}
			const pidMessage = this.formatPid(process.pid);
			const contextMessage = this.formatContext(context);
			const timestampDiff = this.updateAndGetTimestampDiff();
			const formattedLogLevel = logLevel.toUpperCase().padStart(7, ' ');
			const formattedMessage = this.formatMessage(
				logLevel,
				message,
				correlationId,
				pidMessage,
				formattedLogLevel,
				contextMessage,
				timestampDiff,
			);

			process[writeStreamType ?? 'stdout'].write(formattedMessage);
		});
	}

	protected printAsJson(
		message: unknown,
		correlationId: string,
		options: {
			context: string;
			logLevel: LogLevel;
			writeStreamType?: 'stdout' | 'stderr';
			errorStack?: unknown;
		},
	) {
		type JsonLogObject = {
			level: LogLevel;
			pid: number;
			timestamp: number;
			correlationId: string;
			message: unknown;
			context?: string;
			stack?: unknown;
		};

		const logObject: JsonLogObject = {
			level: options.logLevel,
			pid: process.pid,
			timestamp: Date.now(),
			correlationId,
			message,
		};

		if (options.context) {
			logObject.context = options.context;
		}

		if (options.errorStack) {
			logObject.stack = options.errorStack;
		}

		const formattedMessage =
			!this.options.colors && this.inspectOptions.compact === true
				? JSON.stringify(logObject, this.stringifyReplacer)
				: inspect(logObject, this.inspectOptions);
		process[options.writeStreamType ?? 'stdout'].write(`${formattedMessage}\n`);
	}

	protected formatPid(pid: number) {
		return `[${this.options.prefix}] ${pid}  - `;
	}

	protected formatContext(context: string): string {
		if (!context) {
			return '';
		}

		context = `[${context}] `;
		return this.options.colors ? yellow(context) : context;
	}

	protected formatMessage(
		logLevel: LogLevel,
		message: unknown,
		correlationId: string,
		pidMessage: string,
		formattedLogLevel: string,
		contextMessage: string,
		timestampDiff: string,
	) {
		const output = this.stringifyMessage(message, logLevel);
		pidMessage = this.colorize(pidMessage, logLevel);
		formattedLogLevel = this.colorize(formattedLogLevel, logLevel);
		return `${pidMessage}${this.getTimestamp()} ${formattedLogLevel} ${correlationId}${contextMessage}${output}${timestampDiff}\n`;
	}

	protected stringifyMessage(message: unknown, logLevel: LogLevel): string {
		if (isFunction(message)) {
			const messageAsStr = Function.prototype.toString.call(message);
			const isClass = messageAsStr.startsWith('class ');
			if (isClass) {
				// @ts-ignore
				return this.stringifyMessage(message.name, logLevel);
			}
			// @ts-ignore
			return this.stringifyMessage(message(), logLevel);
		}

		if (typeof message === 'string') {
			return this.colorize(message, logLevel);
		}

		const outputText = inspect(message, this.inspectOptions);
		if (isPlainObject(message)) {
			return `Object(${Object.keys(message).length}) ${outputText}`;
		}
		if (Array.isArray(message)) {
			return `Array(${message.length}) ${outputText}`;
		}
		return outputText;
	}

	protected colorize(message: string, logLevel: LogLevel) {
		if (!this.options.colors || this.options.json) {
			return message;
		}
		const color = this.getColorByLogLevel(logLevel);
		return color(message);
	}

	protected printStackTrace(stack: string) {
		if (!stack || this.options.json) {
			return;
		}
		process.stderr.write(`${stack}\n`);
	}

	protected updateAndGetTimestampDiff(): string {
		// @ts-ignore
		const includeTimestamp = ConsoleLogger.lastTimestampAt && this.options?.timestamp;
		const result = includeTimestamp
			? // @ts-ignore
				this.formatTimestampDiff(Date.now() - ConsoleLogger.lastTimestampAt!)
			: '';
		// @ts-ignore
		ConsoleLogger.lastTimestampAt = Date.now();
		return result;
	}

	protected formatTimestampDiff(timestampDiff: number) {
		const formattedDiff = ` +${timestampDiff}ms`;
		return this.options.colors ? yellow(formattedDiff) : formattedDiff;
	}

	protected getInspectOptions() {
		let breakLength = this.options.breakLength;
		if (typeof breakLength === 'undefined') {
			breakLength = this.options.colors
				? this.options.compact
					? Infinity
					: undefined
				: this.options.compact === false
					? undefined
					: Infinity;
		}

		const inspectOptions: InspectOptions = {
			depth: this.options.depth ?? DEFAULT_DEPTH,
			sorted: this.options.sorted,
			showHidden: this.options.showHidden,
			compact: this.options.compact ?? (this.options.json ? true : false),
			colors: this.options.colors,
			breakLength,
		};

		if (this.options.maxArrayLength) {
			inspectOptions.maxArrayLength = this.options.maxArrayLength;
		}
		if (this.options.maxStringLength) {
			inspectOptions.maxStringLength = this.options.maxStringLength;
		}

		return inspectOptions;
	}

	protected stringifyReplacer(_: string, value: unknown) {
		if (typeof value === 'bigint') {
			return value.toString();
		}
		if (typeof value === 'symbol') {
			return value.toString();
		}

		if (value instanceof Map || value instanceof Set || value instanceof Error) {
			return `${inspect(value, this.inspectOptions)}`;
		}
		return value;
	}

	private getContextAndMessagesToPrint(args: unknown[]) {
		if (args?.length <= 1) {
			return { messages: args, context: this.context };
		}
		const lastElement = args[args.length - 1];
		const isContext = isString(lastElement);
		if (!isContext) {
			return { messages: args, context: this.context };
		}
		return {
			context: lastElement,
			messages: args.slice(0, args.length - 1),
		};
	}

	private getContextAndStackAndMessagesToPrint(args: unknown[]) {
		if (args.length === 2) {
			return this.isStackFormat(args[1])
				? {
						messages: [args[0]],
						stack: args[1] as string,
						context: this.context,
					}
				: {
						messages: [args[0]],
						context: args[1] as string,
					};
		}

		const { messages, context } = this.getContextAndMessagesToPrint(args);
		if (messages?.length <= 1) {
			return { messages, context };
		}
		const lastElement = messages[messages.length - 1];
		const isStack = isString(lastElement);
		if (!isStack && !isUndefined(lastElement)) {
			return { messages, context };
		}
		return {
			stack: lastElement,
			messages: messages.slice(0, messages.length - 1),
			context,
		};
	}

	private isStackFormat(stack: unknown) {
		if (!isString(stack) && !isUndefined(stack)) {
			return false;
		}

		return /^(.)+\n\s+at .+:\d+:\d+/.test(stack!);
	}

	private getColorByLogLevel(level: LogLevel) {
		switch (level) {
			case 'debug':
				return clc.magentaBright;
			case 'warn':
				return clc.yellow;
			case 'error':
				return clc.red;
			case 'verbose':
				return clc.cyanBright;
			case 'fatal':
				return clc.bold;
			default:
				return clc.green;
		}
	}
}

