/* eslint-disable @typescript-eslint/no-unnecessary-condition */
import { AsyncLocalStorage } from 'async_hooks';

import { ROLLBAR } from '@constants/common.constant';

export interface RollbarOptions {
	/**
	 * Custom fields to be merged with other event-specific fields.
	 * These fields are searchable in the Rollbar dashboard.
	 *
	 * @example
	 * fields: { accountId: 123, clientName: 'accounts-ui' }
	 */
	fields?: Record<string, number | string | boolean>;

	/**
	 * Custom data to be merged with other event-specific data.
	 * This can include any additional context or metadata for the event.
	 *
	 * @example
	 * data: { sessionId: "abc123", failedConstraints: { email: ['email must be an email'] } }
	 */
	data?: Record<string, unknown>;

	/**
	 * A custom string to be added to Rollbar's default fingerprint.
	 * This is useful for resolving issues with over-grouping of events.
	 *
	 * @example
	 * fingerprintContext: "custom-fingerprint"
	 */
	fingerprintContext?: string;

	/**
	 * A custom title for the issue, which will appear in the Rollbar dashboard.
	 *
	 * @example
	 * issueTitle: "Unexpected Error in Payment Processing"
	 */
	issueTitle?: string;

	/**
	 * A list of entity names. If a NotFoundError is caused by any of these entities,
	 * the corresponding Rollbar event will be ignored and not logged.
	 *
	 * @example
	 * notFoundErrorsIgnoredEntities: ["User", "Order"]
	 */
	notFoundErrorsIgnoredEntities?: string[];
}

export interface RequestStore {
	rollbar: RollbarOptions | undefined;
	[key: string]: unknown;
}

const defaultStoreValue: RequestStore = {
	[ROLLBAR]: undefined,
};

export function deepClone<T>(obj: T): T {
	if (obj === null || obj === undefined || typeof obj !== 'object') return obj;

	const str = JSON.stringify(obj);
	return JSON.parse(str) as T;
}

export function mergeObjectsDeeply<T extends Record<string, unknown>>(
	target: T,
	source: T,
): T {
	if (!target || typeof target !== 'object') {
		return source;
	}

	if (!source || typeof source !== 'object') {
		return target;
	}

	for (const key in source) {
		if (source[key] && typeof source[key] === 'object') {
			target[key] = mergeObjectsDeeply(target[key] || {}, source[key]) as T[Extract<
				keyof T,
				string
			>];
		} else {
			target[key] = source[key];
		}
	}
	return target;
}

export const requestStore = {
	asyncLocalStorage: new AsyncLocalStorage<RequestStore>(),

	set<T extends keyof RequestStore>(key: T, value: RequestStore[T]): void {
		const currentStore = this.asyncLocalStorage.getStore();
		if (currentStore) {
			currentStore[key] = value;
		} else {
			this.asyncLocalStorage.enterWith({ ...defaultStoreValue, [key]: value });
		}
	},

	getOrThrow<T extends keyof RequestStore>(key: T): RequestStore[T] {
		const currentStore = this.getStoreOrThrow();
		const value = currentStore[key];
		if (!value) {
			throw new Error(`Store value for key ${key} is not set`);
		}
		return value;
	},

	get<T extends keyof RequestStore>(key: T): RequestStore[T] {
		const currentStore = this.asyncLocalStorage.getStore();
		return currentStore?.[key];
	},

	update<T extends keyof RequestStore>(key: T, updates: Partial<RequestStore[T]>): void {
		if (key !== ROLLBAR) {
			throw new Error(`Key ${key} is not supported`);
		}
		const currentRollbar = deepClone(this.get(key)) ?? ({} as RollbarOptions);
		const updatedRollbar = mergeObjectsDeeply(updates, currentRollbar) as RollbarOptions;
		this.set('rollbar', updatedRollbar);
	},

	getStoreOrThrow(): RequestStore {
		const currentStore = this.asyncLocalStorage.getStore();
		if (!currentStore) {
			throw new Error('Store is not initialized');
		}
		return currentStore;
	},

	initializeStore(initStoreValues: Partial<RequestStore> = {}): void {
		this.asyncLocalStorage.enterWith({ ...defaultStoreValue, ...initStoreValues });
	},

	run(store: RequestStore, callback: () => void): void {
		this.asyncLocalStorage.run(store, callback);
	},
};

