import { performance } from 'perf_hooks';

import { Logger } from '@nestjs/common';
import * as Rollbar from 'rollbar';

import { rollbar } from '@config/rollbar.config';

import { EXECUTION_TIME_THRESHOLD_MS } from '@constants/env-variables.constant';

export interface LogExecutionOptions<TParams, TResponse> {
	logParams?: boolean;
	logResponse?: boolean;
	logExecutionTime?: boolean;
	logErrToRollbar?: boolean;
	logLongExecution?: boolean;
	rollbarLevel?: 'debug' | 'info' | 'warning' | 'error';
	maskSensitiveData?: boolean;
	sensitiveKeys?: string[];
	customContext?: Record<string, unknown>;
	paramFormatter?: (params: TParams) => unknown;
	responseFormatter?: (response: TResponse) => unknown;
}

const DEFAULT_OPTIONS: LogExecutionOptions<unknown, unknown> = {
	logParams: true,
	logResponse: true,
	logExecutionTime: true,
	logErrToRollbar: true,
	logLongExecution: true,
	rollbarLevel: 'debug',
	maskSensitiveData: true,
	sensitiveKeys: [
		'password',
		'pass',
		'token',
		'secret',
		'auth',
		'authorization',
		'cookie',
		'session',
		'credentials',
		'apiKey',
		'_cookie',
		'csrf',
		'_csrf',
	],
	paramFormatter: <TParams>(params: TParams) => params,
	responseFormatter: <TResponse>(response: TResponse) => response,
};

const thresholdMs = Number(process.env[EXECUTION_TIME_THRESHOLD_MS]);

export function LogExecution<TParams, TResponse>(
	options: LogExecutionOptions<TParams, TResponse> = {},
): MethodDecorator {
	const config: LogExecutionOptions<TParams, TResponse> = {
		...DEFAULT_OPTIONS,
		...options,
	};

	return function (
		target: unknown,
		propertyKey: string | symbol,
		descriptor: PropertyDescriptor,
	) {
		const originalMethod = descriptor.value as (...args: unknown[]) => unknown;
		const className = (target as { constructor: { name: string } }).constructor.name;
		const methodName = String(propertyKey);
		const logger = new Logger(`${className}.${methodName}`);

		descriptor.value = async function (...args: unknown[]) {
			const startTime = performance.now();

			try {
				const logContext = {
					className,
					methodName,
					timestamp: new Date().toISOString(),
					...(config.customContext ?? {}),
				};

				let paramsToLog: unknown = config.paramFormatter
					? config.paramFormatter(args as TParams)
					: args;
				if (config.maskSensitiveData) {
					paramsToLog = maskSensitiveData(paramsToLog, config.sensitiveKeys);
				}

				if (config.logParams) {
					logger.log(
						`[LogExecution]: Method invoked with parameters, ${JSON.stringify({
							params: paramsToLog,
							...logContext,
						})}`,
					);
				}

				const result = await originalMethod.apply(this, args);
				const endTime = performance.now();
				const executionTime = endTime - startTime;

				let responseToLog: unknown = config.responseFormatter
					? config.responseFormatter(result as TResponse)
					: result;
				if (config.maskSensitiveData) {
					responseToLog = maskSensitiveData(responseToLog, config.sensitiveKeys);
				}

				const successLogContext = {
					...logContext,
					executionTimeMs: executionTime,
					response: config.logResponse ? responseToLog : undefined,
				};

				if (config.logExecutionTime) {
					logger.log(
						`[LogExecution]:Method completed in ${executionTime.toFixed(2)}ms. Result: ${JSON.stringify(successLogContext)}`,
					);
				}

				if (executionTime > thresholdMs) {
					logger.warn(
						`[LogExecution]: Long execution ${executionTime.toFixed(
							2,
						)}ms, logContext: ${JSON.stringify({ ...successLogContext, success: true })}`,
					);

					if (config.logLongExecution) {
						try {
							const rollbar = getRollbarInstance();
							if (rollbar) {
								rollbar.warning(
									`[LogExecution]: Long execution ${executionTime.toFixed(2)}ms.`,
									{ ...successLogContext, success: true },
								);
							}
						} catch {}
					}
				}

				return result;
			} catch (error) {
				const endTime = performance.now();
				const executionTime = endTime - startTime;
				const errorLogContext = {
					className,
					methodName,
					timestamp: new Date().toISOString(),
					executionTimeMs: executionTime,
					error: {
						message: (error as Error).message,
						stack: (error as Error).stack,
						name: (error as Error).name,
					},
					...(config.customContext ?? {}),
				};

				logger.error(
					`[LogExecution]: Method failed after ${executionTime.toFixed(2)}ms: ${
						(error as Error).message
					}, errorLogContext: ${JSON.stringify(errorLogContext)}`,
				);

				if (config.logErrToRollbar) {
					try {
						const rollbar = getRollbarInstance();
						if (rollbar) {
							rollbar.error(`Method ${className}.${methodName} failed.`, error as Error, {
								...errorLogContext,
								success: false,
							});
						}
					} catch {}
				}

				throw error;
			}
		};

		return descriptor;
	};
}

function maskSensitiveData(data: unknown, sensitiveKeys: string[] = []): unknown {
	if (!data || typeof data !== 'object') {
		return data;
	}

	if (Array.isArray(data)) {
		return data.map((item) => maskSensitiveData(item, sensitiveKeys));
	}

	const masked = { ...data } as Record<string, unknown>;

	for (const key in masked) {
		if (Object.prototype.hasOwnProperty.call(masked, key)) {
			const lowerKey = key.toLowerCase();

			if (
				sensitiveKeys.some((sensitiveKey) =>
					lowerKey.includes(sensitiveKey.toLowerCase()),
				)
			) {
				masked[key] = '***MASKED***';
			} else if (typeof masked[key] === 'object' && masked[key] !== null) {
				masked[key] = maskSensitiveData(masked[key], sensitiveKeys);
			}
		}
	}

	return masked;
}

function getRollbarInstance(): Rollbar | null {
	return rollbar;
}

