import { performance } from 'perf_hooks';

import { Logger } from '@nestjs/common';

const EXECUTION_TIME_THRESHOLD_MS = 3000;

export interface LogExecutionOptions<TParams = unknown, TResponse = unknown> {
	logParams?: boolean;
	logResponse?: boolean;
	logExecutionTime?: boolean;
	maskSensitiveData?: boolean;
	sensitiveKeys?: string[];
	customContext?: Record<string, unknown>;
	paramFormatter?: (params: TParams) => unknown;
	responseFormatter?: (response: TResponse) => unknown;
}

const DEFAULT_SENSITIVE_KEYS: string[] = [
	'password',
	'pass',
	'token',
	'secret',
	'auth',
	'authorization',
	'cookie',
	'session',
	'credentials',
	'apiKey',
	'csrf',
	'refreshToken',
	'accessToken',
];

const DEFAULT_OPTIONS: LogExecutionOptions = {
	logParams: true,
	logResponse: true,
	logExecutionTime: true,
	maskSensitiveData: true,
	sensitiveKeys: DEFAULT_SENSITIVE_KEYS,
};

const REQUEST_LIKE_KEYS = new Set([
	'raw',
	'socket',
	'headers',
	'hostname',
	'ip',
	'protocol',
	'routeOptions',
	'routerPath',
]);

function isRequestObject(value: unknown): boolean {
	if (!value || typeof value !== 'object') return false;
	const keys = Object.keys(value as Record<string, unknown>);
	return REQUEST_LIKE_KEYS.has(keys[0] ?? '') && keys.length > 5;
}

function isResponseObject(value: unknown): boolean {
	if (!value || typeof value !== 'object') return false;
	const obj = value as Record<string, unknown>;
	return typeof obj['send'] === 'function' && typeof obj['status'] === 'function';
}

function extractRequestInfo(req: Record<string, unknown>): Record<string, unknown> {
	return {
		method: req['method'],
		url: req['url'],
		ip: req['ip'],
		userAgent: (req['headers'] as Record<string, unknown> | undefined)?.['user-agent'],
	};
}

function sanitizeArgs(args: unknown[]): unknown[] {
	return args.map((arg) => {
		if (isRequestObject(arg)) return extractRequestInfo(arg as Record<string, unknown>);
		if (isResponseObject(arg)) return '[FastifyReply]';
		return arg;
	});
}

export function maskSensitiveData(
	data: unknown,
	sensitiveKeys: string[] = DEFAULT_SENSITIVE_KEYS,
): unknown {
	if (!data || typeof data !== 'object') return data;

	if (Array.isArray(data)) {
		return data.map((item) => maskSensitiveData(item, sensitiveKeys));
	}

	const masked = { ...data } as Record<string, unknown>;

	for (const key in masked) {
		if (!Object.prototype.hasOwnProperty.call(masked, key)) continue;

		const lowerKey = key.toLowerCase();

		if (sensitiveKeys.some((sk) => lowerKey.includes(sk.toLowerCase()))) {
			masked[key] = '***MASKED***';
		} else if (typeof masked[key] === 'object' && masked[key] !== null) {
			masked[key] = maskSensitiveData(masked[key], sensitiveKeys);
		}
	}

	return masked;
}

export function LogExecution<TParams = unknown, TResponse = unknown>(
	options: LogExecutionOptions<TParams, TResponse> = {},
): MethodDecorator {
	const config = { ...DEFAULT_OPTIONS, ...options };

	return function (
		target: unknown,
		propertyKey: string | symbol,
		descriptor: PropertyDescriptor,
	): PropertyDescriptor {
		const originalMethod = descriptor.value as (...args: unknown[]) => unknown;
		const className = (target as { constructor: { name: string } }).constructor.name;
		const methodName = String(propertyKey);
		const logger = new Logger(`${className}.${methodName}`);

		descriptor.value = async function (...args: unknown[]) {
			const startTime = performance.now();

			try {
				const logContext = {
					className,
					methodName,
					timestamp: new Date().toISOString(),
					...(config.customContext ?? {}),
				};

				if (config.logParams) {
					let paramsToLog: unknown = config.paramFormatter
						? config.paramFormatter(args as TParams)
						: sanitizeArgs(args);

					if (config.maskSensitiveData) {
						paramsToLog = maskSensitiveData(paramsToLog, config.sensitiveKeys);
					}

					logger.log(
						`Invoked | ${JSON.stringify({ params: paramsToLog, ...logContext })}`,
					);
				}

				const result = await originalMethod.apply(this, args);
				const executionTime = performance.now() - startTime;

				if (config.logExecutionTime) {
					let responseToLog: unknown = config.responseFormatter
						? config.responseFormatter(result as TResponse)
						: result;

					if (config.maskSensitiveData) {
						responseToLog = maskSensitiveData(responseToLog, config.sensitiveKeys);
					}

					const successContext = {
						...logContext,
						executionTimeMs: Math.round(executionTime * 100) / 100,
						...(config.logResponse ? { response: responseToLog } : {}),
					};

					logger.log(
						`Completed in ${executionTime.toFixed(2)}ms | ${JSON.stringify(successContext)}`,
					);
				}

				if (executionTime > EXECUTION_TIME_THRESHOLD_MS) {
					logger.warn(
						`Slow execution: ${executionTime.toFixed(2)}ms | ${className}.${methodName}`,
					);
				}

				return result;
			} catch (error) {
				const executionTime = performance.now() - startTime;

				logger.error(
					`Failed after ${executionTime.toFixed(2)}ms: ${(error as Error).message}`,
					(error as Error).stack,
				);

				throw error;
			}
		};

		return descriptor;
	};
}

