import { Environment } from '@interfaces/env-variables.interface';

export const isTestEnv = (): boolean => process.env['NODE_ENV'] === Environment.TEST;

export const isProdEnv = (): boolean =>
	process.env['NODE_ENV'] === Environment.PRODUCTION;

