@Injectable()
export class CorrelationIdMiddleware implements NestMiddleware {
	use(req: FastifyRequest['raw'], _: FastifyReply['raw'], next: () => void): void {
		const correlationIdFromHeader = req.headers[CORRELATION_ID_HEADER_NAME] as string;

		const id = correlationIdFromHeader || randomUUID();

		correlator.withId({
			correlationId: id,
			fn: () => {
				next();
			},
		});
	}
}

import { IncomingHttpHeaders } from 'node:http2';

import { Logger } from '@nestjs/common';
import { FastifyRequest, FastifyReply, FastifyPluginCallback } from 'fastify';
import { HttpHeader } from 'fastify/types/utils';
import fp from 'fastify-plugin';

import { isDevEnv } from '@utils/common.util';

const FIELDS_WITH_SENSITIVE_DATA = [
	'req.body.password',
	'req.body.email',
	'req.body.tenant',
	'req.body.recipient',
	'req.headers.cookie',
	'req.headers.authorization',
	'req.headers.proxyAuthorization',
	'res.headers.cookie',
	'res.headers["set-cookie"]',
	'res.headers.authorization',
	'res.headers.proxyAuthorization',
];

export const logHttpRequest = (
	req: FastifyRequest,
	res: FastifyReply,
	error?: Error,
): void => {
	const logger = new Logger('HTTP Request');
	const body = req.body ?? {};
	const requestHeaders = req.headers;
	const method = req.method;
	const url = req.url;
	const originalUrl = req.originalUrl;
	const responseHeaders = res.getHeaders();
	const statusCode = res.statusCode;
	const ips = req.ips;
	const ip = req.ip;

	const validateHeaders = (
		headers:
			| IncomingHttpHeaders
			| Record<HttpHeader, string | number | string[] | undefined>,
	): Record<string, string> =>
		Object.entries(headers).reduce<Record<string, string>>((acc, [key, value]) => {
			if (FIELDS_WITH_SENSITIVE_DATA.includes(`req.headers.${key}`)) {
				acc[key] = isDevEnv() ? JSON.stringify(value) : '*****';
			} else {
				acc[key] = JSON.stringify(value);
			}
			return acc;
		}, {});

	const validatedBody = Object.entries(body).reduce<Record<string, string>>(
		(acc, [key, value]) => {
			if (FIELDS_WITH_SENSITIVE_DATA.includes(`req.body.${key}`)) {
				acc[key] = isDevEnv() ? JSON.stringify(value) : '*****';
			} else {
				acc[key] = JSON.stringify(value);
			}
			return acc;
		},
		{},
	);

	const isErrorStatus = statusCode >= 400;
	const logMethod = isErrorStatus || error ? 'error' : 'log';

	const logData: Record<string, unknown> = {
		req: {
			method,
			url,
			originalUrl,
			ips,
			ip,
			headers: validateHeaders(requestHeaders),
			body: validatedBody,
		},
		res: { statusCode, headers: validateHeaders(responseHeaders) },
	};

	if (error) {
		logData['error'] = {
			message: error.message,
			name: error.name,
			stack: error.stack,
		};
	}

	logger[logMethod](logData);
};

const httpLoggerPlugin: FastifyPluginCallback = (fastify, _options, done) => {
	fastify.addHook('onResponse', (request, reply, done) => {
		if (reply.statusCode === 404) {
			const notFoundError = new Error(
				`Route not found: ${request.method} ${request.url}`,
			);
			notFoundError.name = 'NotFoundError';
			logHttpRequest(request, reply, notFoundError);
		} else {
			logHttpRequest(request, reply);
		}
		done();
	});

	fastify.addHook('onError', (request, reply, error, done) => {
		logHttpRequest(request, reply, error);
		done();
	});

	done();
};

export const fastifyHttpLogger = fp(httpLoggerPlugin, {
	name: 'fastify-http-logger',
});

