import { randomUUID } from 'node:crypto';
import { Injectable, NestMiddleware } from '@nestjs/common';
import { correlator } from 'correlation-id-ts';
import { FastifyRequest, FastifyReply } from 'fastify';
import { CORRELATION_ID_HEADER_NAME } from '@constants/req.constants';

@Injectable()
export class CorrelationIdMiddleware implements NestMiddleware {
	use(req: FastifyRequest['raw'], _: FastifyReply['raw'], next: () => void): void {
		const correlationIdFromHeader = req.headers[CORRELATION_ID_HEADER_NAME] as string;
		const id = correlationIdFromHeader || randomUUID();
		correlator.withId({
			correlationId: id,
			fn: () => { next(); },
		});
	}
}
