import { Logger } from '@nestjs/common';

import { fastifyHttpLogger, logHttpRequest } from '@middlewares/logger.middleware';

import type { FastifyInstance, FastifyReply, FastifyRequest } from 'fastify';

jest.mock('@utils/common.util', () => ({
	isDevEnv: jest.fn(),
}));

import { isDevEnv } from '@utils/common.util';

const mockIsDevEnv = isDevEnv as jest.MockedFunction<typeof isDevEnv>;

function createMockRequest(overrides: Partial<FastifyRequest> = {}): FastifyRequest {
	return {
		method: 'GET',
		url: '/api/test',
		originalUrl: '/api/test',
		ips: ['10.0.0.1'],
		ip: '127.0.0.1',
		headers: {
			'content-type': 'application/json',
			'user-agent': 'jest-test',
		},
		body: {},
		...overrides,
	} as unknown as FastifyRequest;
}

function createMockReply(overrides: Partial<FastifyReply> = {}): FastifyReply {
	return {
		statusCode: 200,
		getHeaders: jest.fn().mockReturnValue({
			'content-type': 'application/json',
		}),
		...overrides,
	} as unknown as FastifyReply;
}

describe('logger.middleware', () => {
	let logSpy: jest.SpyInstance;
	let errorSpy: jest.SpyInstance;

	beforeEach(() => {
		mockIsDevEnv.mockReturnValue(false);
		logSpy = jest.spyOn(Logger.prototype, 'log').mockImplementation(jest.fn());
		errorSpy = jest.spyOn(Logger.prototype, 'error').mockImplementation(jest.fn());
	});

	afterEach(() => {
		jest.clearAllMocks();
	});

	describe('logHttpRequest', () => {
		describe('logging method selection', () => {
			it('should use Logger.log when status code is below 400 and no error', () => {
				const req = createMockRequest();
				const res = createMockReply({ statusCode: 200 });

				logHttpRequest(req, res);

				expect(logSpy).toHaveBeenCalledTimes(1);
				expect(errorSpy).not.toHaveBeenCalled();
			});

			it('should use Logger.log when status code is 399', () => {
				const req = createMockRequest();
				const res = createMockReply({ statusCode: 399 });

				logHttpRequest(req, res);

				expect(logSpy).toHaveBeenCalledTimes(1);
				expect(errorSpy).not.toHaveBeenCalled();
			});

			it('should use Logger.error when status code is 400', () => {
				const req = createMockRequest();
				const res = createMockReply({ statusCode: 400 });

				logHttpRequest(req, res);

				expect(errorSpy).toHaveBeenCalledTimes(1);
				expect(logSpy).not.toHaveBeenCalled();
			});

			it('should use Logger.error when status code is 500', () => {
				const req = createMockRequest();
				const res = createMockReply({ statusCode: 500 });

				logHttpRequest(req, res);

				expect(errorSpy).toHaveBeenCalledTimes(1);
				expect(logSpy).not.toHaveBeenCalled();
			});

			it('should use Logger.error when error is provided even with 200 status', () => {
				const req = createMockRequest();
				const res = createMockReply({ statusCode: 200 });
				const error = new Error('something went wrong');

				logHttpRequest(req, res, error);

				expect(errorSpy).toHaveBeenCalledTimes(1);
				expect(logSpy).not.toHaveBeenCalled();
			});
		});

		describe('request data logging', () => {
			it('should log method, url, originalUrl, ips, ip', () => {
				const req = createMockRequest({
					method: 'POST',
					url: '/api/users',
					originalUrl: '/api/users?foo=bar',
					ips: ['192.168.1.1', '10.0.0.1'],
					ip: '192.168.1.1',
				});
				const res = createMockReply();

				logHttpRequest(req, res);

				expect(logSpy).toHaveBeenCalledWith(
					expect.objectContaining({
						req: expect.objectContaining({
							method: 'POST',
							url: '/api/users',
							originalUrl: '/api/users?foo=bar',
							ips: ['192.168.1.1', '10.0.0.1'],
							ip: '192.168.1.1',
						}),
					}),
				);
			});

			it('should log response statusCode', () => {
				const req = createMockRequest();
				const res = createMockReply({ statusCode: 201 });

				logHttpRequest(req, res);

				expect(logSpy).toHaveBeenCalledWith(
					expect.objectContaining({
						res: expect.objectContaining({
							statusCode: 201,
						}),
					}),
				);
			});

			it('should call getHeaders to retrieve response headers', () => {
				const req = createMockRequest();
				const mockGetHeaders = jest.fn().mockReturnValue({ 'x-custom': 'value' });
				const res = createMockReply({ getHeaders: mockGetHeaders });

				logHttpRequest(req, res);

				expect(mockGetHeaders).toHaveBeenCalledTimes(1);
			});

			it('should use empty object when request body is null/undefined', () => {
				const req = createMockRequest({ body: undefined as unknown as null });
				const res = createMockReply();

				logHttpRequest(req, res);

				expect(logSpy).toHaveBeenCalledWith(
					expect.objectContaining({
						req: expect.objectContaining({
							body: {},
						}),
					}),
				);
			});

			it('should log non-sensitive body fields as JSON stringified values', () => {
				const req = createMockRequest({
					body: { username: 'johndoe', age: 30 },
				});
				const res = createMockReply();

				logHttpRequest(req, res);

				expect(logSpy).toHaveBeenCalledWith(
					expect.objectContaining({
						req: expect.objectContaining({
							body: {
								username: '"johndoe"',
								age: '30',
							},
						}),
					}),
				);
			});

			it('should log non-sensitive request headers as JSON stringified values', () => {
				const req = createMockRequest({
					headers: { 'content-type': 'application/json' },
				});
				const res = createMockReply();

				logHttpRequest(req, res);

				expect(logSpy).toHaveBeenCalledWith(
					expect.objectContaining({
						req: expect.objectContaining({
							headers: expect.objectContaining({
								'content-type': '"application/json"',
							}),
						}),
					}),
				);
			});

			it('should log non-sensitive response headers as JSON stringified values', () => {
				const res = createMockReply({
					statusCode: 200,
					getHeaders: jest.fn().mockReturnValue({ 'x-request-id': 'abc123' }),
				});
				const req = createMockRequest();

				logHttpRequest(req, res);

				expect(logSpy).toHaveBeenCalledWith(
					expect.objectContaining({
						res: expect.objectContaining({
							headers: expect.objectContaining({
								'x-request-id': '"abc123"',
							}),
						}),
					}),
				);
			});
		});

		describe('sensitive data masking in non-dev env', () => {
			beforeEach(() => {
				mockIsDevEnv.mockReturnValue(false);
			});

			it('should mask password in request body', () => {
				const req = createMockRequest({ body: { password: 'secret123' } });
				const res = createMockReply();

				logHttpRequest(req, res);

				expect(logSpy).toHaveBeenCalledWith(
					expect.objectContaining({
						req: expect.objectContaining({
							body: { password: '*****' },
						}),
					}),
				);
			});

			it('should mask email in request body', () => {
				const req = createMockRequest({ body: { email: 'user@example.com' } });
				const res = createMockReply();

				logHttpRequest(req, res);

				expect(logSpy).toHaveBeenCalledWith(
					expect.objectContaining({
						req: expect.objectContaining({
							body: { email: '*****' },
						}),
					}),
				);
			});

			it('should mask tenant in request body', () => {
				const req = createMockRequest({ body: { tenant: 'my-tenant' } });
				const res = createMockReply();

				logHttpRequest(req, res);

				expect(logSpy).toHaveBeenCalledWith(
					expect.objectContaining({
						req: expect.objectContaining({
							body: { tenant: '*****' },
						}),
					}),
				);
			});

			it('should mask recipient in request body', () => {
				const req = createMockRequest({ body: { recipient: 'someone@example.com' } });
				const res = createMockReply();

				logHttpRequest(req, res);

				expect(logSpy).toHaveBeenCalledWith(
					expect.objectContaining({
						req: expect.objectContaining({
							body: { recipient: '*****' },
						}),
					}),
				);
			});

			it('should mask cookie in request headers', () => {
				const req = createMockRequest({ headers: { cookie: 'session=abc' } });
				const res = createMockReply();

				logHttpRequest(req, res);

				expect(logSpy).toHaveBeenCalledWith(
					expect.objectContaining({
						req: expect.objectContaining({
							headers: { cookie: '*****' },
						}),
					}),
				);
			});

			it('should mask authorization in request headers', () => {
				const req = createMockRequest({ headers: { authorization: 'Bearer token123' } });
				const res = createMockReply();

				logHttpRequest(req, res);

				expect(logSpy).toHaveBeenCalledWith(
					expect.objectContaining({
						req: expect.objectContaining({
							headers: { authorization: '*****' },
						}),
					}),
				);
			});

			it('should mask proxyAuthorization in request headers', () => {
				const req = createMockRequest({
					headers: { proxyAuthorization: 'Basic creds' },
				});
				const res = createMockReply();

				logHttpRequest(req, res);

				expect(logSpy).toHaveBeenCalledWith(
					expect.objectContaining({
						req: expect.objectContaining({
							headers: { proxyAuthorization: '*****' },
						}),
					}),
				);
			});

			it('should mask cookie in response headers', () => {
				const res = createMockReply({
					statusCode: 200,
					getHeaders: jest.fn().mockReturnValue({ cookie: 'session=xyz' }),
				});
				const req = createMockRequest();

				logHttpRequest(req, res);

				expect(logSpy).toHaveBeenCalledWith(
					expect.objectContaining({
						res: expect.objectContaining({
							headers: { cookie: '*****' },
						}),
					}),
				);
			});

			it('should mask authorization in response headers', () => {
				const res = createMockReply({
					statusCode: 200,
					getHeaders: jest.fn().mockReturnValue({ authorization: 'Bearer resp-token' }),
				});
				const req = createMockRequest();

				logHttpRequest(req, res);

				expect(logSpy).toHaveBeenCalledWith(
					expect.objectContaining({
						res: expect.objectContaining({
							headers: { authorization: '*****' },
						}),
					}),
				);
			});

			it('should mask proxyAuthorization in response headers', () => {
				const res = createMockReply({
					statusCode: 200,
					getHeaders: jest.fn().mockReturnValue({ proxyAuthorization: 'proxy-creds' }),
				});
				const req = createMockRequest();

				logHttpRequest(req, res);

				expect(logSpy).toHaveBeenCalledWith(
					expect.objectContaining({
						res: expect.objectContaining({
							headers: { proxyAuthorization: '*****' },
						}),
					}),
				);
			});

			it('should mask multiple sensitive fields simultaneously', () => {
				const req = createMockRequest({
					headers: { cookie: 'session=abc', authorization: 'Bearer tkn' },
					body: { email: 'a@b.com', password: 'pass', username: 'johndoe' },
				});
				const res = createMockReply();

				logHttpRequest(req, res);

				expect(logSpy).toHaveBeenCalledWith(
					expect.objectContaining({
						req: expect.objectContaining({
							headers: { cookie: '*****', authorization: '*****' },
							body: { email: '*****', password: '*****', username: '"johndoe"' },
						}),
					}),
				);
			});
		});

		describe('sensitive data shown in dev env', () => {
			beforeEach(() => {
				mockIsDevEnv.mockReturnValue(true);
			});

			it('should show actual password value in request body', () => {
				const req = createMockRequest({ body: { password: 'secret123' } });
				const res = createMockReply();

				logHttpRequest(req, res);

				expect(logSpy).toHaveBeenCalledWith(
					expect.objectContaining({
						req: expect.objectContaining({
							body: { password: '"secret123"' },
						}),
					}),
				);
			});

			it('should show actual email value in request body', () => {
				const req = createMockRequest({ body: { email: 'user@example.com' } });
				const res = createMockReply();

				logHttpRequest(req, res);

				expect(logSpy).toHaveBeenCalledWith(
					expect.objectContaining({
						req: expect.objectContaining({
							body: { email: '"user@example.com"' },
						}),
					}),
				);
			});

			it('should show actual cookie value in request headers', () => {
				const req = createMockRequest({ headers: { cookie: 'session=abc' } });
				const res = createMockReply();

				logHttpRequest(req, res);

				expect(logSpy).toHaveBeenCalledWith(
					expect.objectContaining({
						req: expect.objectContaining({
							headers: { cookie: '"session=abc"' },
						}),
					}),
				);
			});

			it('should show actual authorization value in request headers', () => {
				const req = createMockRequest({ headers: { authorization: 'Bearer devtoken' } });
				const res = createMockReply();

				logHttpRequest(req, res);

				expect(logSpy).toHaveBeenCalledWith(
					expect.objectContaining({
						req: expect.objectContaining({
							headers: { authorization: '"Bearer devtoken"' },
						}),
					}),
				);
			});

			it('should show actual tenant and recipient values in dev env', () => {
				const req = createMockRequest({
					body: { tenant: 'acme-corp', recipient: 'ops@acme.com' },
				});
				const res = createMockReply();

				logHttpRequest(req, res);

				expect(logSpy).toHaveBeenCalledWith(
					expect.objectContaining({
						req: expect.objectContaining({
							body: { tenant: '"acme-corp"', recipient: '"ops@acme.com"' },
						}),
					}),
				);
			});
		});

		describe('error details', () => {
			it('should include error message, name, and stack when error is provided', () => {
				const req = createMockRequest();
				const res = createMockReply({ statusCode: 500 });
				const error = new Error('database connection failed');
				error.name = 'DatabaseError';

				logHttpRequest(req, res, error);

				expect(errorSpy).toHaveBeenCalledWith(
					expect.objectContaining({
						error: {
							message: 'database connection failed',
							name: 'DatabaseError',
							stack: error.stack,
						},
					}),
				);
			});

			it('should not include error key when no error is provided', () => {
				const req = createMockRequest();
				const res = createMockReply();

				logHttpRequest(req, res);

				const logData = (logSpy.mock.calls[0] as [Record<string, unknown>])[0];
				expect(logData).not.toHaveProperty('error');
			});

			it('should include error details on 2xx status when error param is passed', () => {
				const req = createMockRequest();
				const res = createMockReply({ statusCode: 200 });
				const error = new TypeError('unexpected type');

				logHttpRequest(req, res, error);

				expect(errorSpy).toHaveBeenCalledWith(
					expect.objectContaining({
						error: {
							message: 'unexpected type',
							name: 'TypeError',
							stack: error.stack,
						},
					}),
				);
			});
		});
	});

	describe('fastifyHttpLogger', () => {
		let mockFastify: {
			addHook: jest.Mock;
		};
		let capturedHooks: Record<
			string,
			(
				req: FastifyRequest,
				reply: FastifyReply,
				errorOrDone: Error | (() => void),
				done?: () => void,
			) => void
		>;

		beforeEach(() => {
			capturedHooks = {};
			mockFastify = {
				addHook: jest.fn().mockImplementation((hookName, handler) => {
					capturedHooks[hookName as string] = handler;
				}),
			};

			const pluginCallback = fastifyHttpLogger as unknown as (
				fastify: unknown,
				options: unknown,
				done: () => void,
			) => void;
			pluginCallback(mockFastify as unknown as FastifyInstance, {}, () => {});
		});

		describe('plugin registration', () => {
			it('should register an onResponse hook', () => {
				expect(mockFastify.addHook).toHaveBeenCalledWith(
					'onResponse',
					expect.any(Function),
				);
			});

			it('should register an onError hook', () => {
				expect(mockFastify.addHook).toHaveBeenCalledWith(
					'onError',
					expect.any(Function),
				);
			});
		});

		describe('onResponse hook', () => {
			it('should call done after logging', () => {
				const req = createMockRequest();
				const res = createMockReply({ statusCode: 200 });
				const done = jest.fn();

				capturedHooks['onResponse']!(req, res, done);

				expect(done).toHaveBeenCalledTimes(1);
			});

			it('should log normally for non-404 responses', () => {
				const req = createMockRequest({ method: 'GET', url: '/api/users' });
				const res = createMockReply({ statusCode: 200 });
				const done = jest.fn();

				capturedHooks['onResponse']!(req, res, done);

				expect(logSpy).toHaveBeenCalledTimes(1);
				expect(errorSpy).not.toHaveBeenCalled();
			});

			it('should create NotFoundError and log as error for 404 response', () => {
				const req = createMockRequest({ method: 'GET', url: '/api/missing' });
				const res = createMockReply({ statusCode: 404 });
				const done = jest.fn();

				capturedHooks['onResponse']!(req, res, done);

				expect(errorSpy).toHaveBeenCalledTimes(1);
				expect(logSpy).not.toHaveBeenCalled();
			});

			it('should include NotFoundError with correct message for 404', () => {
				const req = createMockRequest({ method: 'DELETE', url: '/api/gone' });
				const res = createMockReply({ statusCode: 404 });
				const done = jest.fn();

				capturedHooks['onResponse']!(req, res, done);

				expect(errorSpy).toHaveBeenCalledWith(
					expect.objectContaining({
						error: expect.objectContaining({
							message: 'Route not found: DELETE /api/gone',
							name: 'NotFoundError',
						}),
					}),
				);
			});

			it('should log error for 500 responses', () => {
				const req = createMockRequest();
				const res = createMockReply({ statusCode: 500 });
				const done = jest.fn();

				capturedHooks['onResponse']!(req, res, done);

				expect(errorSpy).toHaveBeenCalledTimes(1);
			});

			it('should log normally for 201 responses', () => {
				const req = createMockRequest({ method: 'POST', url: '/api/resource' });
				const res = createMockReply({ statusCode: 201 });
				const done = jest.fn();

				capturedHooks['onResponse']!(req, res, done);

				expect(logSpy).toHaveBeenCalledTimes(1);
				expect(errorSpy).not.toHaveBeenCalled();
			});
		});

		describe('onError hook', () => {
			it('should call done after logging', () => {
				const req = createMockRequest();
				const res = createMockReply({ statusCode: 500 });
				const error = new Error('internal error');
				const done = jest.fn();

				capturedHooks['onError']!(req, res, error, done);

				expect(done).toHaveBeenCalledTimes(1);
			});

			it('should log with the provided error', () => {
				const req = createMockRequest();
				const res = createMockReply({ statusCode: 500 });
				const error = new Error('handler crashed');
				const done = jest.fn();

				capturedHooks['onError']!(req, res, error, done);

				expect(errorSpy).toHaveBeenCalledWith(
					expect.objectContaining({
						error: expect.objectContaining({
							message: 'handler crashed',
						}),
					}),
				);
			});

			it('should pass error details including name and stack', () => {
				const req = createMockRequest();
				const res = createMockReply({ statusCode: 422 });
				const error = new RangeError('out of range');
				const done = jest.fn();

