		return true;
	}

	const lastWriteTime = this.recentWrites.get(key);
	if (lastWriteTime) {
		const timeSinceWrite = Date.now() - lastWriteTime;
		return timeSinceWrite < this.CONSISTENCY_WINDOW_MS;
	}

	return false;
}

private trackRecentWrite({ key }: { key: string }): void {
	this.recentWrites.set(key, Date.now());
}

private startRecentWritesCleanup(): void {
	setInterval(() => {
		const now = Date.now();
		for (const [key, timestamp] of this.recentWrites.entries()) {
			if (now - timestamp > this.CONSISTENCY_WINDOW_MS * 2) {
				this.recentWrites.delete(key);
			}
		}
	}, this.CONSISTENCY_WINDOW_MS).unref();
}

private setupHealthChecks(): void {
	this.redisReadClient.on('error', (error) => {
		this.logger.error('Read replica connection error:', error);
		this.isReadReplicaHealthy = false;
	});

	this.redisReadClient.on('ready', () => {
		this.logger.log('Read replica connection restored');
		this.isReadReplicaHealthy = true;
	});

	this.redisWriteClient.on('error', (error) => {
		this.logger.error('Write client connection error:', error);
	});
