import { randomUUID } from 'crypto';

import fastifyCookie from '@fastify/cookie';
import { ValidationPipe } from '@nestjs/common';
import { FastifyAdapter, NestFastifyApplication } from '@nestjs/platform-fastify';
import { Test, TestingModule } from '@nestjs/testing';
import { Redis } from 'ioredis';
import Knex from 'knex';
import * as request from 'supertest';

import { AppModule } from '@modules/app/app.module';
import { FastifyThrottlerGuard } from '@modules/auth/guards/fastify-throttler.guard';
import { REDIS_WRITE_CLIENT } from '@modules/cache/cache.constant';
import { SessionService } from '@modules/session/session.service';
import { ISession } from '@modules/session/types/session.interface';
import { UserService } from '@modules/user/user.service';

import type { App } from 'supertest/types';

import {
	cleanDatabase,
	cleanRedis,
	createAccessToken,
	createSession,
	createTestUser,
	insertCompany,
	insertCompanyMember,
	insertUser,
} from './helpers/auth.helper';

describe('UserModule (e2e)', () => {
	let app: NestFastifyApplication;
	let httpServer: App;
	let knex: Knex.Knex;
	let redis: Redis;
	let moduleFixture: TestingModule;
	let userService: UserService;
	let sessionService: SessionService;

	beforeAll(async () => {
		moduleFixture = await Test.createTestingModule({
			imports: [AppModule],
		})
			.overrideGuard(FastifyThrottlerGuard)
			.useValue({ canActivate: () => true })
			.compile();

		app = moduleFixture.createNestApplication<NestFastifyApplication>(
			new FastifyAdapter(),
		);
		await app.register(fastifyCookie);

		app.useGlobalPipes(
			new ValidationPipe({
				transform: true,
				whitelist: true,
				forbidNonWhitelisted: true,
			}),
		);

		app.setGlobalPrefix('api', { exclude: ['liveness', 'readiness'] });

		await app.init();
		await app.getHttpAdapter().getInstance().ready();

		httpServer = app.getHttpServer() as App;

		knex = Knex({
			client: 'pg',
			connection: process.env['DATABASE_URL']!,
		});

		redis = moduleFixture.get<Redis>(REDIS_WRITE_CLIENT);
		userService = moduleFixture.get<UserService>(UserService);
		sessionService = moduleFixture.get<SessionService>(SessionService);

		await knex.migrate.latest({ directory: './src/migrations' });
	});

	afterAll(async () => {
		await cleanDatabase({ knex });
		await cleanRedis({ redis });
		await knex.destroy();
		await app.close();
	});

	beforeEach(async () => {
		await cleanDatabase({ knex });
		await cleanRedis({ redis });
	});

	describe('GET /api/users/me', () => {
		it('should return user profile and memberships when authenticated', async () => {
			const user = createTestUser({ email: `me-${randomUUID()}@example.com` });
			await insertUser({ knex, user });

			const company = await insertCompany({ knex, name: 'User Company' });
			await insertCompanyMember({
				knex,
				userId: user._id,
				companyId: company._id,
				role: 'admin',
			});

			const sessionId = randomUUID();
			await createSession({
				redis,
				userId: user._id,
				sessionId,
				role: 'admin',
				companyId: company._id,
			});

			const accessToken = createAccessToken({
				userId: user._id,
				sessionId,
				role: 'admin',
				companyId: company._id,
			});

			const response = await request(httpServer)
				.get('/api/users/me')
				.set('Authorization', `Bearer ${accessToken}`)
				.expect(200);

			expect(response.body).toHaveProperty('user');
			expect(response.body).toHaveProperty('memberships');
			expect(response.body.user._id).toBe(user._id);
			expect(response.body.user.email).toBe(user.email);
			expect(Array.isArray(response.body.memberships)).toBe(true);
			expect(response.body.memberships).toHaveLength(1);
			expect(response.body.memberships[0].company_id).toBe(company._id);
		});

		it('should return user profile with empty memberships when user has no memberships', async () => {
			const user = createTestUser({ email: `nomember-${randomUUID()}@example.com` });
			await insertUser({ knex, user });

			const sessionId = randomUUID();
			await createSession({
				redis,
				userId: user._id,
				sessionId,
				role: null,
				companyId: null,
			});

			const accessToken = createAccessToken({
				userId: user._id,
				sessionId,
				role: null,
				companyId: null,
			});

			const response = await request(httpServer)
				.get('/api/users/me')
				.set('Authorization', `Bearer ${accessToken}`)
				.expect(200);

			expect(response.body).toHaveProperty('user');
			expect(response.body).toHaveProperty('memberships');
			expect(response.body.memberships).toHaveLength(0);
		});

		it('should return 401 when unauthenticated', async () => {
			await request(httpServer).get('/api/users/me').expect(401);
		});

		it('should return 401 when JWT is invalid', async () => {
			await request(httpServer)
				.get('/api/users/me')
				.set('Authorization', 'Bearer invalid-jwt-token')
				.expect(401);
		});
	});

	describe('POST /api/users/me/company', () => {
		it('should switch active company when user is a member', async () => {
			const user = createTestUser({ email: `switch-${randomUUID()}@example.com` });
			await insertUser({ knex, user });

			const company1 = await insertCompany({ knex, name: 'Company One' });
			const company2 = await insertCompany({ knex, name: 'Company Two' });

			await insertCompanyMember({
				knex,
				userId: user._id,
				companyId: company1._id,
				role: 'admin',
			});
			await insertCompanyMember({
				knex,
				userId: user._id,
				companyId: company2._id,
				role: 'member',
			});

			const sessionId = randomUUID();
			await createSession({
				redis,
				userId: user._id,
				sessionId,
				role: 'admin',
				companyId: company1._id,
			});

			const accessToken = createAccessToken({
				userId: user._id,
				sessionId,
				role: 'admin',
				companyId: company1._id,
			});

			const response = await request(httpServer)
				.post('/api/users/me/company')
				.set('Authorization', `Bearer ${accessToken}`)
				.send({ company_id: company2._id })
				.expect(201);

			expect(response.body).toEqual({ success: true });
		});

		it('should return 403 when user is not a member of the target company', async () => {
			const user = createTestUser({ email: `switchforbid-${randomUUID()}@example.com` });
			await insertUser({ knex, user });

			const company1 = await insertCompany({ knex, name: 'My Company' });
			const company2 = await insertCompany({ knex, name: 'Not My Company' });

			await insertCompanyMember({
				knex,
				userId: user._id,
				companyId: company1._id,
				role: 'admin',
			});

			const sessionId = randomUUID();
			await createSession({
				redis,
				userId: user._id,
				sessionId,
				role: 'admin',
				companyId: company1._id,
			});

			const accessToken = createAccessToken({
				userId: user._id,
				sessionId,
				role: 'admin',
				companyId: company1._id,
			});

			await request(httpServer)
				.post('/api/users/me/company')
				.set('Authorization', `Bearer ${accessToken}`)
				.send({ company_id: company2._id })
				.expect(403);
		});

		it('should return 401 when unauthenticated', async () => {
			const company = await insertCompany({ knex, name: 'Some Company' });

			await request(httpServer)
				.post('/api/users/me/company')
				.send({ company_id: company._id })
				.expect(401);
		});
	});

	describe('UserService (direct)', () => {
		it('should soft-delete a user', async () => {
			const user = createTestUser({ email: `softdel-user-${randomUUID()}@example.com` });
			await insertUser({ knex, user });

			await userService.softDelete({ userId: user._id });

			const row = await knex('users').where({ _id: user._id }).first();
			expect(row.deleted_at).not.toBeNull();
		});
	});

	describe('SessionService (direct)', () => {
		it('should return null when no sessions exist for destroyAllSessions empty case', async () => {
			const userId = randomUUID();
			await sessionService.destroyAllSessions({ userId });
		});

		it('should destroy session when refreshToken is provided', async () => {
			const userId = randomUUID();
			const sessionId = randomUUID();
			const refreshToken = randomUUID();
			const now = new Date().toISOString();

			const session: ISession = {
				user_id: userId,
				session_id: sessionId,
				role: null,
				company_id: null,
				provider: 'github',
				ip: '127.0.0.1',
				user_agent: 'test',
				created_at: now,
				last_active: now,
			};

			await sessionService.createSession({ session, refreshToken });

			await sessionService.destroySession({ userId, sessionId, refreshToken });

			const result = await redis.get(`session:${userId}:${sessionId}`);
			expect(result).toBeNull();

			const refreshResult = await redis.get(`refresh:${refreshToken}`);
			expect(refreshResult).toBeNull();
		});

		it('should skip updateLastActive when session does not exist', async () => {
			const userId = randomUUID();
			const sessionId = randomUUID();
			await sessionService.updateLastActive({ userId, sessionId });
		});

		it('should skip updateCompanyContext when session does not exist', async () => {
			const userId = randomUUID();
			const sessionId = randomUUID();
			await sessionService.updateCompanyContext({
				userId,
				sessionId,
				companyId: randomUUID(),
				role: 'member',
			});
		});

		it('should destroy sessions by company id', async () => {
			const userId = randomUUID();
			const sessionId1 = randomUUID();
			const sessionId2 = randomUUID();
			const companyId = randomUUID();
			const now = new Date().toISOString();

			const session1: ISession = {
				user_id: userId,
				session_id: sessionId1,
				role: 'admin',
				company_id: companyId,
				provider: 'github',
				ip: '127.0.0.1',
				user_agent: 'test',
				created_at: now,
				last_active: now,
			};

			const session2: ISession = {
				user_id: userId,
				session_id: sessionId2,
				role: null,
				company_id: null,
				provider: 'github',
				ip: '127.0.0.1',
				user_agent: 'test',
				created_at: now,
				last_active: now,
			};

			await sessionService.createSession({
				session: session1,
				refreshToken: randomUUID(),
			});
			await sessionService.createSession({
				session: session2,
				refreshToken: randomUUID(),
			});

			await sessionService.destroySessionsByCompanyId({ userId, companyId });

			const result1 = await redis.get(`session:${userId}:${sessionId1}`);
			expect(result1).toBeNull();

			const result2 = await redis.get(`session:${userId}:${sessionId2}`);
			expect(result2).not.toBeNull();
		});
	});
});

import { randomUUID } from 'crypto';

import fastifyCookie from '@fastify/cookie';
import { ValidationPipe } from '@nestjs/common';
import { FastifyAdapter, NestFastifyApplication } from '@nestjs/platform-fastify';
import { Test, TestingModule } from '@nestjs/testing';
import { Redis } from 'ioredis';
import Knex from 'knex';
import * as request from 'supertest';

import { AppModule } from '@modules/app/app.module';
import { FastifyThrottlerGuard } from '@modules/auth/guards/fastify-throttler.guard';
import { REDIS_WRITE_CLIENT } from '@modules/cache/cache.constant';
import { CompanyService } from '@modules/company/company.service';
import { CompanyMemberService } from '@modules/company-member/company-member.service';

import type { App } from 'supertest/types';

import {
	cleanDatabase,
	cleanRedis,
	createAccessToken,
	createSession,
	createTestUser,
	insertCompany,
	insertCompanyMember,
	insertUser,
} from './helpers/auth.helper';

describe('CompanyModule (e2e)', () => {
	let app: NestFastifyApplication;
	let httpServer: App;
	let knex: Knex.Knex;
	let redis: Redis;
	let moduleFixture: TestingModule;
	let companyService: CompanyService;
	let companyMemberService: CompanyMemberService;

	beforeAll(async () => {
		moduleFixture = await Test.createTestingModule({
			imports: [AppModule],
		})
			.overrideGuard(FastifyThrottlerGuard)
			.useValue({ canActivate: () => true })
			.compile();

		app = moduleFixture.createNestApplication<NestFastifyApplication>(
			new FastifyAdapter(),
		);
		await app.register(fastifyCookie);

		app.useGlobalPipes(
			new ValidationPipe({
				transform: true,
				whitelist: true,
				forbidNonWhitelisted: true,
			}),
		);

		app.setGlobalPrefix('api', { exclude: ['liveness', 'readiness'] });

		await app.init();
		await app.getHttpAdapter().getInstance().ready();

		httpServer = app.getHttpServer() as App;

		knex = Knex({
			client: 'pg',
			connection: process.env['DATABASE_URL']!,
		});

		redis = moduleFixture.get<Redis>(REDIS_WRITE_CLIENT);
		companyService = moduleFixture.get<CompanyService>(CompanyService);
		companyMemberService = moduleFixture.get<CompanyMemberService>(CompanyMemberService);

		await knex.migrate.latest({ directory: './src/migrations' });
	});

	afterAll(async () => {
		await cleanDatabase({ knex });
		await cleanRedis({ redis });
		await knex.destroy();
		await app.close();
	});

	beforeEach(async () => {
		await cleanDatabase({ knex });
		await cleanRedis({ redis });
	});

	describe('GET /api/companies/:id', () => {
		it('should return company details when user is a member', async () => {
			const user = createTestUser({ email: `member-${randomUUID()}@example.com` });
			await insertUser({ knex, user });

			const company = await insertCompany({ knex, name: 'Test Company' });
			await insertCompanyMember({
				knex,
				userId: user._id,
				companyId: company._id,
				role: 'admin',
			});

			const sessionId = randomUUID();
			await createSession({
				redis,
				userId: user._id,
				sessionId,
				role: 'admin',
				companyId: company._id,
			});

			const accessToken = createAccessToken({
				userId: user._id,
				sessionId,
				role: 'admin',
				companyId: company._id,
			});

			const response = await request(httpServer)
				.get(`/api/companies/${company._id}`)
				.set('Authorization', `Bearer ${accessToken}`)
				.expect(200);

			expect(response.body._id).toBe(company._id);
			expect(response.body.name).toBe('Test Company');
		});

		it('should return 403 when user is not a member of the company', async () => {
			const user = createTestUser({ email: `nonmember-${randomUUID()}@example.com` });
			await insertUser({ knex, user });

			const ownCompany = await insertCompany({ knex, name: 'My Company' });
			await insertCompanyMember({
				knex,
				userId: user._id,
				companyId: ownCompany._id,
				role: 'admin',
			});

			const otherCompany = await insertCompany({ knex, name: 'Other Company' });

			const sessionId = randomUUID();
			await createSession({
				redis,
				userId: user._id,
				sessionId,
				role: 'admin',
				companyId: ownCompany._id,
			});

			const accessToken = createAccessToken({
				userId: user._id,
				sessionId,
				role: 'admin',
				companyId: ownCompany._id,
			});

			await request(httpServer)
				.get(`/api/companies/${otherCompany._id}`)
				.set('Authorization', `Bearer ${accessToken}`)
				.expect(403);
		});

		it('should return 403 when querying a company the user has no membership for', async () => {
			const user = createTestUser({ email: `notfound-${randomUUID()}@example.com` });
			await insertUser({ knex, user });

			const company = await insertCompany({ knex, name: 'Existing Company' });
			await insertCompanyMember({
				knex,
				userId: user._id,
				companyId: company._id,
				role: 'member',
			});

			const sessionId = randomUUID();
			await createSession({
				redis,
				userId: user._id,
				sessionId,
				role: 'member',
				companyId: company._id,
			});

			const accessToken = createAccessToken({
				userId: user._id,
				sessionId,
				role: 'member',
				companyId: company._id,
			});

			const nonExistentId = randomUUID();

			await request(httpServer)
				.get(`/api/companies/${nonExistentId}`)
				.set('Authorization', `Bearer ${accessToken}`)
				.expect(403);
		});

		it('should return 404 when user has membership but company has been soft-deleted', async () => {
			const user = createTestUser({ email: `softdel-${randomUUID()}@example.com` });
			await insertUser({ knex, user });

			const company = await insertCompany({ knex, name: 'Deleted Company' });
			await insertCompanyMember({
				knex,
				userId: user._id,
				companyId: company._id,
				role: 'member',
			});

			await knex('companies')
				.where({ _id: company._id })
				.update({ deleted_at: knex.fn.now() });

			const sessionId = randomUUID();
			await createSession({
				redis,
				userId: user._id,
				sessionId,
				role: 'member',
				companyId: company._id,
			});

			const accessToken = createAccessToken({
				userId: user._id,
				sessionId,
				role: 'member',
				companyId: company._id,
			});

			await request(httpServer)
				.get(`/api/companies/${company._id}`)
				.set('Authorization', `Bearer ${accessToken}`)
				.expect(404);
		});

		it('should return 401 when unauthenticated', async () => {
			const company = await insertCompany({ knex, name: 'Auth Company' });

			await request(httpServer).get(`/api/companies/${company._id}`).expect(401);
		});
	});

	describe('CompanyService (direct)', () => {
		it('should soft-delete a company', async () => {
			const company = await companyService.create({ data: { name: 'To Delete' } });

			await companyService.softDelete({ companyId: company._id });

			const row = await knex('companies').where({ _id: company._id }).first();
			expect(row.deleted_at).not.toBeNull();
		});
	});

	describe('CompanyMemberService (direct)', () => {
		it('should find members by company id', async () => {
			const user = createTestUser({ email: `cmlist-${randomUUID()}@example.com` });
			await insertUser({ knex, user });

			const company = await companyService.create({ data: { name: 'CM List Co' } });
			await companyMemberService.create({
				data: { user_id: user._id, company_id: company._id, role: 'member' },
			});

			await new Promise<void>((resolve) => setTimeout(resolve, 150));

			const members = await companyMemberService.findByCompanyId({
				companyId: company._id,
			});
			expect(members).toHaveLength(1);
			expect(members[0]!.user_id).toBe(user._id);
		});

		it('should find admin by company id', async () => {
			const user = createTestUser({ email: `cmadmin-${randomUUID()}@example.com` });
			await insertUser({ knex, user });

			const company = await companyService.create({ data: { name: 'CM Admin Co' } });
			await companyMemberService.create({
				data: { user_id: user._id, company_id: company._id, role: 'admin' },
			});

			await new Promise<void>((resolve) => setTimeout(resolve, 150));

			const admin = await companyMemberService.findAdminByCompanyId({
				companyId: company._id,
			});
			expect(admin).not.toBeNull();
			expect(admin?.user_id).toBe(user._id);
		});

		it('should return null when no admin exists for company', async () => {
			const company = await companyService.create({ data: { name: 'No Admin Co' } });

			const admin = await companyMemberService.findAdminByCompanyId({
				companyId: company._id,
			});
			expect(admin).toBeNull();
		});

		it('should soft-delete a company member by id', async () => {
			const user = createTestUser({ email: `cmsoftdel-${randomUUID()}@example.com` });
			await insertUser({ knex, user });

			const company = await companyService.create({ data: { name: 'CM SoftDel Co' } });
			const member = await companyMemberService.create({
				data: { user_id: user._id, company_id: company._id, role: 'member' },
			});

			await companyMemberService.softDelete({ companyMemberId: member._id });

			const row = await knex('company_members').where({ _id: member._id }).first();
			expect(row.deleted_at).not.toBeNull();
		});

		it('should soft-delete a company member by user and company', async () => {
			const user = createTestUser({ email: `cmbyuserc-${randomUUID()}@example.com` });
			await insertUser({ knex, user });

			const company = await companyService.create({ data: { name: 'CM ByUser Co' } });
			await companyMemberService.create({
				data: { user_id: user._id, company_id: company._id, role: 'member' },
			});

			await companyMemberService.softDeleteByUserAndCompany({
				userId: user._id,
				companyId: company._id,
			});

			const row = await knex('company_members')
				.where({ user_id: user._id, company_id: company._id })
				.first();
			expect(row.deleted_at).not.toBeNull();
		});

		it('should create a company member with a transaction', async () => {
			const user = createTestUser({ email: `cmtrx-${randomUUID()}@example.com` });
			await insertUser({ knex, user });

			const company = await companyService.create({ data: { name: 'CM Trx Co' } });

			const knexConn = Knex({
				client: 'pg',
				connection: process.env['DATABASE_URL']!,
			});

			try {
				const trx = await knexConn.transaction();
				const member = await companyMemberService.createWithTransaction({
					trx,
					data: { user_id: user._id, company_id: company._id, role: 'member' },
				});
				await trx.commit();

				expect(member._id).toBeDefined();
				expect(member.user_id).toBe(user._id);
			} finally {
				await knexConn.destroy();
			}
		});
	});
});

