@LogExecution({ logParams: false, logResponse: false })
async exchangeToken(
	@Body() dto: TokenExchangeDto,
	@Req() request: FastifyRequest,
	@Res() reply: FastifyReply,
): Promise<void> {
	const result = await this.authService.exchangeCode({
		code: dto.code,
		ip: request.ip,
		userAgent: request.headers['user-agent'] ?? '',
		provider: 'github',
	});

	reply.setCookie(REFRESH_TOKEN_COOKIE_NAME, result.refreshToken, {
		httpOnly: true,
		secure: !isDevEnv(),
		sameSite: 'strict',
		path: '/api/auth',
		maxAge: 30 * 24 * 60 * 60,
	});

	reply.send({ access_token: result.accessToken });
}

@Public()
@Throttle({ default: { limit: 5, ttl: 60000 } })
@Post('refresh')
@ApiOperation({ summary: 'Refresh access token using refresh token cookie' })
@ApiResponse({
	status: HttpStatus.OK,
	description: 'Returns new access token, rotates refresh cookie',
})
@ApiResponse({
	status: HttpStatus.UNAUTHORIZED,
	description: 'No or invalid refresh token',
})
@LogExecution({ logParams: false, logResponse: false })
async refresh(
	@Req() request: FastifyRequest,
	@Res() reply: FastifyReply,
): Promise<void> {
	const refreshToken = (request.cookies as Record<string, string>)[
		REFRESH_TOKEN_COOKIE_NAME
	];
	if (!refreshToken) throw new UnauthorizedException('No refresh token');

	const result = await this.authService.refreshTokens({ refreshToken });

	reply.setCookie(REFRESH_TOKEN_COOKIE_NAME, result.refreshToken, {
		httpOnly: true,
		secure: !isDevEnv(),
		sameSite: 'strict',
		path: '/api/auth',
		maxAge: 30 * 24 * 60 * 60,
	});

	reply.send({ access_token: result.accessToken });
}

