import {
	CanActivate,
	ExecutionContext,
	Injectable,
	UnauthorizedException,
} from '@nestjs/common';
import { Reflector } from '@nestjs/core';
import { JwtService } from '@nestjs/jwt';

import { IS_PUBLIC_KEY } from '@modules/auth/decorators/public.decorator';
import { IJwtPayload, IRequestUser } from '@modules/auth/types/auth.interface';
import { SessionService } from '@modules/session/session.service';

import type { FastifyRequest } from 'fastify';

@Injectable()
export class AuthGuard implements CanActivate {
	constructor(
		private readonly jwtService: JwtService,
		private readonly sessionService: SessionService,
		private readonly reflector: Reflector,
	) {}

	async canActivate(context: ExecutionContext): Promise<boolean> {
		const isPublic = this.reflector.getAllAndOverride<boolean>(IS_PUBLIC_KEY, [
			context.getHandler(),
			context.getClass(),
		]);

		const request = context
			.switchToHttp()
			.getRequest<FastifyRequest & { user?: IRequestUser }>();
		const token = this.extractTokenFromHeader(request);

		if (isPublic) {
			if (token) {
				await this.tryPopulateUser({ request, token });
			}
			return true;
		}

		if (!token) throw new UnauthorizedException();

		let payload: IJwtPayload;
		try {
			payload = await this.jwtService.verifyAsync<IJwtPayload>(token);
		} catch {
			throw new UnauthorizedException();
		}

		const session = await this.sessionService.getSession({
			userId: payload.user_id,
			sessionId: payload.session_id,
		});
		if (!session) throw new UnauthorizedException();

		request.user = {
			user_id: payload.user_id,
			session_id: payload.session_id,
			role: session.role,
			company_id: session.company_id,
		} satisfies IRequestUser;

		return true;
	}

	private async tryPopulateUser({
		request,
		token,
	}: {
		request: FastifyRequest & { user?: IRequestUser };
		token: string;
	}): Promise<void> {
		const payload = await this.jwtService
			.verifyAsync<IJwtPayload>(token)
			.catch(() => null);
		if (!payload) return;

		const session = await this.sessionService.getSession({
			userId: payload.user_id,
			sessionId: payload.session_id,
		});
		if (!session) return;

		request.user = {
			user_id: payload.user_id,
			session_id: payload.session_id,
			role: session.role,
			company_id: session.company_id,
		} satisfies IRequestUser;
	}

	private extractTokenFromHeader({ headers }: FastifyRequest): string | null {
		const [type, token] = headers.authorization?.split(' ') ?? [];
		return type === 'Bearer' ? (token ?? null) : null;
	}
}

