private setCsrfCookie({ reply }: { reply: FastifyReply }): void {
	const token = randomBytes(32).toString('hex');
	reply.setCookie(CSRF_TOKEN_COOKIE_NAME, token, {
		httpOnly: false,
		secure: !isDevEnv(),
		sameSite: isDevEnv() ? 'lax' : 'none',
		path: '/',
		maxAge: 30 * 24 * 60 * 60,
	});
}

