import { ExecutionContext, ForbiddenException } from '@nestjs/common';

import { CsrfGuard } from '@modules/auth/guards/csrf.guard';

const makeContext = ({
	csrfHeader,
	csrfCookie,
}: {
	csrfHeader?: string;
	csrfCookie?: string;
}): ExecutionContext =>
	({
		switchToHttp: () => ({
			getRequest: () => ({
				headers: { 'x-csrf-token': csrfHeader },
				cookies: { csrf_token: csrfCookie },
			}),
		}),
	}) as unknown as ExecutionContext;

describe('CsrfGuard', () => {
	let guard: CsrfGuard;

	beforeEach(() => {
		guard = new CsrfGuard();
	});

	it('should return true when header matches cookie', () => {
		const ctx = makeContext({ csrfHeader: 'abc123', csrfCookie: 'abc123' });
		expect(guard.canActivate(ctx)).toBe(true);
	});

	it('should throw ForbiddenException when header is missing', () => {
		const ctx = makeContext({ csrfHeader: undefined, csrfCookie: 'abc123' });
		expect(() => guard.canActivate(ctx)).toThrow(ForbiddenException);
	});

	it('should throw ForbiddenException when cookie is missing', () => {
		const ctx = makeContext({ csrfHeader: 'abc123', csrfCookie: undefined });
		expect(() => guard.canActivate(ctx)).toThrow(ForbiddenException);
	});

	it('should throw ForbiddenException when header and cookie do not match', () => {
		const ctx = makeContext({ csrfHeader: 'abc123', csrfCookie: 'xyz789' });
		expect(() => guard.canActivate(ctx)).toThrow(ForbiddenException);
	});
});

