	it('should return new tokens with valid refresh cookie', async () => {
		const user = createTestUser({ email: `refresh-${randomUUID()}@example.com` });
		await insertUser({ knex, user });

		const sessionId = randomUUID();
		const refreshToken = await createSession({
			redis,
			userId: user._id,
			sessionId,
			role: null,
			companyId: null,
		});

		const response = await request(httpServer)
			.post('/api/auth/refresh')
			.set('Cookie', `${REFRESH_TOKEN_COOKIE_NAME}=${refreshToken}`)
			.expect(201);

		expect(response.body).toHaveProperty('access_token');
		expect(response.headers['set-cookie']).toBeDefined();
	});

	it('should return 401 when no refresh cookie is present', async () => {
		await request(httpServer).post('/api/auth/refresh').expect(401);
	});

	it('should return 401 for invalid refresh token', async () => {
		await request(httpServer)
			.post('/api/auth/refresh')
			.set('Cookie', `${REFRESH_TOKEN_COOKIE_NAME}=invalid-token`)
			.expect(401);
	});

	it('should return 401 and destroy session when reusing a rotated refresh token', async () => {
		const user = createTestUser({ email: `reuse-${randomUUID()}@example.com` });
		await insertUser({ knex, user });

		const sessionId = randomUUID();
		const refreshToken = await createSession({
			redis,
			userId: user._id,
			sessionId,
			role: null,
			companyId: null,
		});

		const firstRefreshResponse = await request(httpServer)
			.post('/api/auth/refresh')
			.set('Cookie', `${REFRESH_TOKEN_COOKIE_NAME}=${refreshToken}`)
			.expect(201);

		expect(firstRefreshResponse.body).toHaveProperty('access_token');

		await request(httpServer)
			.post('/api/auth/refresh')
			.set('Cookie', `${REFRESH_TOKEN_COOKIE_NAME}=${refreshToken}`)
			.expect(401);

		const sessionData = await redis.get(`session:${user._id}:${sessionId}`);
		expect(sessionData).toBeNull();
	});
});

