		expect(response.body).toEqual({ success: true });

		const sessionData = await redis.get(`session:${user._id}:${sessionId}`);
		expect(sessionData).toBeNull();
	});

	it('should return 401 when unauthenticated', async () => {
		await request(httpServer).post('/api/auth/logout').expect(401);
	});
});

