export async function createSession({
	redis,
	userId,
	sessionId,
	role,
	companyId,
}: {
	redis: Redis;
	userId: string;
	sessionId: string;
	role: 'admin' | 'member' | null;
	companyId: string | null;
}): Promise<string> {
	const refreshToken = randomUUID();
	const now = new Date().toISOString();

	const session: ISession = {
		user_id: userId,
		session_id: sessionId,
		role,
		company_id: companyId,
		provider: 'github',
		ip: '127.0.0.1',
		user_agent: 'test-agent',
		created_at: now,
		last_active: now,
	};

	const payload = { user_id: userId, session_id: sessionId };

	await redis
		.multi()
		.set(`session:${userId}:${sessionId}`, JSON.stringify(session), 'EX', SESSION_TTL)
		.sadd(`sessions:${userId}`, sessionId)
		.set(`refresh:${refreshToken}`, JSON.stringify(payload), 'EX', SESSION_TTL)

