	@LogExecution()
	async logout(
		@CurrentUser() user: IRequestUser,
		@Res() reply: FastifyReply,
	): Promise<void> {
		await this.authService.logout({
			userId: user.user_id,
			sessionId: user.session_id,
		});
		this.clearAuthCookies({ reply });
		reply.send({ success: true });
	}

	@Post('logout/all')
	@ApiOperation({ summary: 'Log out all sessions for current user' })
	@ApiResponse({ status: HttpStatus.OK, description: 'All sessions terminated' })
	@LogExecution()
	async logoutAll(
